@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ServiceWaitingScreen(
    serviceId: Long,
    onBackHome: () -> Unit,
    onNavigateToStreaming: (Long) -> Unit
) {
    val viewModel: ServiceWaitingViewModel = viewModel()
    val uiState by viewModel.uiState.collectAsState()
    val service = uiState.service
    val status = service?.status?.uppercase().orEmpty()
    val canCancel = status in cancellableStatuses
    val isTerminal = status in terminalStatuses

    LaunchedEffect(serviceId) {
        viewModel.load(serviceId)
    }

    // Auto-navigate to streaming when status is READY
    LaunchedEffect(status) {
        if (status == "READY") {
            onNavigateToStreaming(serviceId)
        }
    }

    Scaffold(
        containerColor = Background,
        topBar = {
            TopAppBar(
                title = { Text("Service status", color = TextPrimary, fontWeight = FontWeight.Bold) },
                colors = TopAppBarDefaults.topAppBarColors(containerColor = Background)
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(14.dp)
        ) {
            if (uiState.isLoading) {
                CircularProgressIndicator(color = PrimaryAccent)
                Text("Loading your active request...", color = TextSecondary)
            }

            uiState.error?.let { message ->
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(containerColor = Color(0xFFFFEBEE))
                ) {
                    Text(
                        text = message,
                        color = Color(0xFFC62828),
                        modifier = Modifier.padding(12.dp)
                    )
                }
            }

            uiState.infoMessage?.let { message ->
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(containerColor = Color(0xFFE8F5E9))
                ) {
                    Text(
                        text = message,
                        color = Color(0xFF2E7D32),
                        modifier = Modifier.padding(12.dp)
                    )
                }
            }

            if (service != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(containerColor = CardBackground)
                ) {
                    Column(
                        modifier = Modifier.padding(14.dp),
                        verticalArrangement = Arrangement.spacedBy(8.dp)
                    ) {
                        StatusBadge(status = service.status)
                        Text("Status: ${service.status}", color = TextPrimary, fontWeight = FontWeight.SemiBold)
                        Text(
                            text = when (status) {
                                "REQUESTED" -> "Waiting for a partner to accept your request."
                                "ACCEPTED" -> "A partner accepted your request. Waiting for tour start."
                                "READY" -> "Partner is ready! Starting streaming..."
                                "STARTED" -> "Tour is in progress."
                                "COMPLETED" -> "Tour finished successfully."
                                "CANCELLED" -> "Tour was cancelled."
                                else -> "Checking latest status..."
                            },
                            color = TextSecondary
                        )
                        Text("Location: ${service.startLocationDescription ?: "Not specified"}", color = TextSecondary)
                    }
                }
            }

            if (canCancel && !isTerminal) {
                OutlinedButton(
                    onClick = { viewModel.cancelService() },
                    enabled = !uiState.isCancelling,
                    modifier = Modifier.fillMaxWidth()
                ) {
                    if (uiState.isCancelling) {
                        CircularProgressIndicator(color = Color(0xFFC62828))
                    } else {
                        Text("Cancel tour", color = Color(0xFFC62828))
                    }
                }
            }

            OutlinedButton(
                onClick = { viewModel.manualRefresh() },
                enabled = !uiState.isRefreshing && !uiState.isLoading,
                modifier = Modifier.fillMaxWidth()
            ) {
                Text(if (uiState.isRefreshing) "Refreshing..." else "Refresh status")
            }

            Button(
                onClick = onBackHome,
                modifier = Modifier.fillMaxWidth()
            ) {
                Text("Back to home")
            }
        }
    }
}

@Composable
private fun StatusBadge(status: String) {
    val normalized = status.uppercase()
    val label = if (normalized == "REQUESTED") "CREATED" else normalized
    val (bg, fg) = when (normalized) {
        "REQUESTED" -> Color(0xFF263238) to Color(0xFF90CAF9)
        "ACCEPTED" -> Color(0xFF1B5E20) to Color(0xFFA5D6A7)
        "READY" -> Color(0xFF4CAF50) to Color(0xFFE8F5E9)
        "STARTED" -> Color(0xFF4E342E) to Color(0xFFFFCC80)
        "COMPLETED" -> Color(0xFF0D47A1) to Color(0xFFBBDEFB)
        "CANCELLED" -> Color(0xFFB71C1C) to Color(0xFFFFCDD2)
        else -> Color(0xFF37474F) to Color(0xFFECEFF1)
    }

    Card(colors = CardDefaults.cardColors(containerColor = bg)) {
        Text(
            text = label,
            color = fg,
            fontWeight = FontWeight.Bold,
            modifier = Modifier.padding(horizontal = 10.dp, vertical = 4.dp)
        )
    }
}

package com.sismptm.client.data.remote
import retrofit2.Response import retrofit2.http.Body import retrofit2.http.GET import retrofit2.http.POST import retrofit2.http.Path
interface ApiService {
/** POST /api/clients/register */ @POST("api/clients/register") suspend fun registerClient(@Body request: RegisterClientRequest): Response<RegisterClientResponse>
/** POST /api/auth/client/login */ @POST("api/auth/client/login") suspend fun loginClient(@Body request: LoginRequest): Response<LoginResponse>
/** POST /api/services/create - requires CLIENT token */ @POST("api/services/create") suspend fun createService(@Body request: CreateServiceRequest): Response<ServiceResponse>
/** GET /api/clients/profile */ @GET("api/clients/profile") suspend fun getUserProfile(): UserProfileResponse
/** GET /api/users/me */ @GET("api/users/me") suspend fun getMyProfile(): UserProfileResponse
/** GET /api/services/client/{clientId} - requires CLIENT token */ @GET("api/services/client/{clientId}") suspend fun getServicesByClient(@Path("clientId") clientId: Long): Response<List<ServiceResponse>>
/** GET /api/services/{serviceId} - requires CLIENT/PARTNER token */ @GET("api/services/{serviceId}") suspend fun getServiceById(@Path("serviceId") serviceId: Long): Response<ServiceResponse>
/** POST /api/services/{serviceId}/cancel - requires CLIENT token */ @POST("api/services/{serviceId}/cancel") suspend fun cancelService(@Path("serviceId") serviceId: Long): Response<ServiceResponse> }
// -- Auth DTOs ----------------------------------------------------------------- data class LoginRequest(val email: String, val password: String)
data class LoginResponse( val accessToken: String, val refreshToken: String, val tokenType: String, val expiresIn: Long, val id: Long, val email: String, val name: String, val role: String )
// Request DTO (mirrors RegisterClientRequest from backend) data class RegisterClientRequest( val email: String, val password: String, val name: String, val termsAccepted: Boolean, val language: String, val picDirectory: String? = null )
// Response DTO (mirrors RegisterClientResponse from backend) data class RegisterClientResponse( val id: Long, val email: String, val name: String, val status: String, val language: String, val createdAt: String, val termsAccepted: Boolean, val picDirectory: String?, val role: String )
// -- Service DTOs -------------------------------------------------------------- data class CreateServiceRequest( val clientId: Long, val longitude: Double, val latitude: Double, val startLocationDescription: String?, val agreedHours: Int, val hourlyRate: Double )
data class ServiceResponse( val serviceId: Long, val clientId: Long, val clientName: String? = null, val partnerId: Long?, val longitude: Double, val latitude: Double, val startLocationDescription: String?, val agreedHours: Int, val hourlyRate: Double, val status: String, val requestedAt: String?, val acceptedAt: String?, val startedAt: String?, val endedAt: String? )
data class UserProfileResponse( val id: Int, val name: String, val email: String, val status: String, val language: String, val role: String, val picDirectory: String? )

